# plugin_interface.py
"""
插件接口定义 - 定义所有插件必须实现的标准接口
"""

from abc import ABC, abstractmethod
from enum import Enum
from typing import Any, Dict, List, Optional
from dataclasses import dataclass, field
from datetime import datetime


class PluginState(Enum):
    """插件状态枚举"""
    UNLOADED = "unloaded"      # 未加载
    LOADING = "loading"        # 加载中
    LOADED = "loaded"          # 已加载（未启用）
    ENABLING = "enabling"      # 启用中
    ENABLED = "enabled"        # 已启用
    DISABLING = "disabling"    # 停用中
    DISABLED = "disabled"      # 已停用
    ERROR = "error"            # 错误状态
    UPDATING = "updating"      # 更新中
    UNINSTALLING = "uninstalling"  # 卸载中


class PluginPriority(Enum):
    """插件优先级"""
    CRITICAL = 0      # 关键插件（如日志、核心服务）
    HIGH = 100        # 高优先级
    NORMAL = 200      # 普通优先级
    LOW = 300         # 低优先级


@dataclass
class PluginInfo:
    """插件元信息"""
    plugin_id: str                           # 插件唯一标识
    name: str                                 # 插件名称
    version: str                             # 版本号 (语义化版本)
    description: str = ""                    # 描述
    author: str = ""                         # 作者
    dependencies: List[str] = field(default_factory=list)  # 必需依赖的插件ID列表
    optional_deps: List[str] = field(default_factory=list) # 可选依赖列表
    priority: PluginPriority = PluginPriority.NORMAL       # 优先级
    supported_api_versions: List[str] = field(default_factory=list)  # 支持的API版本
    min_framework_version: str = "1.0.0"     # 最低框架版本要求
    tags: List[str] = field(default_factory=list)         # 标签
    metadata: Dict[str, Any] = field(default_factory=dict)  # 自定义元数据
    loaded_at: Optional[datetime] = None     # 加载时间
    enabled_at: Optional[datetime] = None    # 启用时间
    error_message: Optional[str] = None     # 错误信息

    def __hash__(self):
        return hash(self.plugin_id)

    def __eq__(self, other):
        if isinstance(other, PluginInfo):
            return self.plugin_id == other.plugin_id
        return False

    def satisfies_version_requirement(self, version: str) -> bool:
        """检查是否满足最低版本要求"""
        return self._compare_versions(version, self.min_framework_version) >= 0

    @staticmethod
    def _compare_versions(v1: str, v2: str) -> int:
        """比较语义化版本号：v1 > v2 返回 1，v1 < v2 返回 -1，相等返回 0"""
        def parse(v):
            return [int(x) for x in v.split('.')]

        parts1, parts2 = parse(v1), parse(v2)
        # 补齐长度
        while len(parts1) < 3:
            parts1.append(0)
        while len(parts2) < 3:
            parts2.append(0)

        for p1, p2 in zip(parts1, parts2):
            if p1 > p2:
                return 1
            elif p1 < p2:
                return -1
        return 0


class PluginContext:
    """插件上下文 - 提供插件运行所需的环境"""

    def __init__(self, plugin_id: str, framework_version: str):
        self.plugin_id = plugin_id
        self.framework_version = framework_version
        self._services: Dict[str, Any] = {}
        self._config: Dict[str, Any] = {}
        self._resources: Dict[str, Any] = {}
        self._event_handlers: Dict[str, List] = {}
        self._shared_data: Dict[str, Any] = {}

    def register_service(self, name: str, service: Any) -> None:
        """注册服务供其他插件使用"""
        self._services[name] = service

    def get_service(self, name: str, default: Any = None) -> Optional[Any]:
        """获取已注册的服务"""
        return self._services.get(name, default)

    def unregister_service(self, name: str) -> bool:
        """注销服务"""
        if name in self._services:
            del self._services[name]
            return True
        return False

    def get_config(self, key: str, default: Any = None) -> Any:
        """获取配置值"""
        return self._config.get(key, default)

    def set_config(self, key: str, value: Any) -> None:
        """设置配置值"""
        self._config[key] = value

    def allocate_resource(self, name: str, resource: Any) -> None:
        """分配资源"""
        self._resources[name] = resource

    def release_resource(self, name: str) -> None:
        """释放资源"""
        if name in self._resources:
            del self._resources[name]

    def get_shared_data(self, key: str, default: Any = None) -> Any:
        """获取共享数据"""
        return self._shared_data.get(key, default)

    def set_shared_data(self, key: str, value: Any) -> None:
        """设置共享数据"""
        self._shared_data[key] = value

    def clear(self) -> None:
        """清理上下文"""
        self._services.clear()
        self._config.clear()
        self._resources.clear()
        self._event_handlers.clear()
        self._shared_data.clear()


class BasePlugin(ABC):
    """插件基类 - 所有插件必须继承此类"""

    def __init__(self):
        self._info: Optional[PluginInfo] = None
        self._context: Optional[PluginContext] = None
        self._state: PluginState = PluginState.UNLOADED

    @property
    def info(self) -> PluginInfo:
        """获取插件信息"""
        if self._info is None:
            self._info = self.get_plugin_info()
        return self._info

    @property
    def context(self) -> PluginContext:
        """获取插件上下文"""
        if self._context is None:
            raise RuntimeError("Plugin context not initialized")
        return self._context

    @property
    def state(self) -> PluginState:
        """获取插件状态"""
        return self._state

    def _set_state(self, state: PluginState) -> None:
        """内部状态设置"""
        self._state = state

    def _set_context(self, context: PluginContext) -> None:
        """内部上下文设置"""
        self._context = context

    # ==================== 必须实现的方法 ====================

    @abstractmethod
    def get_plugin_info(self) -> PluginInfo:
        """返回插件元信息"""
        pass

    @abstractmethod
    def on_load(self) -> bool:
        """
        插件加载时调用
        返回: True 表示加载成功，False 表示加载失败
        """
        pass

    @abstractmethod
    def on_enable(self) -> bool:
        """
        插件启用时调用
        返回: True 表示启用成功，False 表示启用失败
        """
        pass

    @abstractmethod
    def on_disable(self) -> None:
        """插件停用时调用"""
        pass

    @abstractmethod
    def on_unload(self) -> None:
        """插件卸载时调用"""
        pass

    # ==================== 可选重写的方法 ====================

    def on_update(self, old_version: str) -> bool:
        """
        插件更新时调用
        参数: old_version - 旧版本号
        返回: True 表示更新成功
        """
        return True

    def on_rollback(self, version: str) -> bool:
        """
        插件回滚时调用
        参数: version - 回滚到的版本
        返回: True 表示回滚成功
        """
        return True

    def validate_config(self, config: Dict[str, Any]) -> tuple[bool, Optional[str]]:
        """
        验证配置
        返回: (是否有效, 错误信息)
        """
        return True, None

    def get_api_version(self) -> str:
        """返回插件API版本"""
        return "1.0.0"

    def get_dependencies(self) -> List[str]:
        """返回必需依赖列表（兼容旧接口）"""
        return self.info.dependencies

    def get_optional_dependencies(self) -> List[str]:
        """返回可选依赖列表"""
        return self.info.optional_deps
