# dependency_resolver.py
"""
依赖解析器 - 负责插件依赖的解析和排序
支持必需依赖和可选依赖的分离处理
"""

from typing import Dict, List, Set, Optional, Tuple, Any
from collections import defaultdict
from dataclasses import dataclass, field
from enum import Enum

from plugin_interface import PluginInfo, PluginPriority


class DependencyError(Exception):
    """依赖错误基类"""
    pass


class CycleDetectedError(DependencyError):
    """循环依赖错误"""
    pass


class MissingDependencyError(DependencyError):
    """缺失必需依赖错误"""
    pass


class VersionMismatchError(DependencyError):
    """版本不匹配错误"""
    pass


class CircularDependencyWarning(Warning):
    """循环依赖警告（非致命）"""
    pass


@dataclass
class DependencyNode:
    """依赖节点"""
    info: PluginInfo
    depth: int = 0
    dependents: List['DependencyNode'] = field(default_factory=list)

    def __post_init__(self):
        if self.dependents is None:
            self.dependents = []


@dataclass
class ResolutionResult:
    """解析结果"""
    success: bool
    load_order: List[str] = field(default_factory=list)
    unload_order: List[str] = field(default_factory=list)
    errors: List[str] = field(default_factory=list)
    warnings: List[str] = field(default_factory=list)
    missing_required: List[str] = field(default_factory=list)
    missing_optional: List[str] = field(default_factory=list)


class DependencyResolver:
    """
    依赖解析器
    使用拓扑排序解决插件加载顺序问题
    正确区分必需依赖和可选依赖
    """

    def __init__(self):
        self._plugins: Dict[str, PluginInfo] = {}
        self._nodes: Dict[str, DependencyNode] = {}
        self._optional_deps: Dict[str, Set[str]] = defaultdict(set)  # 新增：记录可选依赖

    def register_plugin(self, info: PluginInfo) -> None:
        """注册插件信息"""
        self._plugins[info.plugin_id] = info
        self._nodes[info.plugin_id] = DependencyNode(info)
        # 记录可选依赖
        self._optional_deps[info.plugin_id] = set(info.optional_deps)

    def unregister_plugin(self, plugin_id: str) -> None:
        """注销插件"""
        if plugin_id in self._plugins:
            del self._plugins[plugin_id]
        if plugin_id in self._nodes:
            del self._nodes[plugin_id]
        if plugin_id in self._optional_deps:
            del self._optional_deps[plugin_id]

    def is_registered(self, plugin_id: str) -> bool:
        """检查插件是否已注册"""
        return plugin_id in self._plugins

    def get_plugin_info(self, plugin_id: str) -> Optional[PluginInfo]:
        """获取插件信息"""
        return self._plugins.get(plugin_id)

    def resolve(self, plugin_ids: List[str]) -> ResolutionResult:
        """
        解析依赖并返回加载顺序
        使用改进的拓扑排序，考虑优先级
        返回: ResolutionResult 包含解析结果和警告信息
        """
        result = ResolutionResult(success=True)

        # 验证所有必需依赖是否存在
        missing_required, missing_optional = self._validate_dependencies(plugin_ids)
        result.missing_required = missing_required
        result.missing_optional = missing_optional

        # 如果有缺失的必需依赖，解析失败
        if missing_required:
            result.success = False
            result.errors = [f"Missing required dependency: {dep}" for dep in missing_required]
            return result

        # 如果有缺失的可选依赖，记录警告
        if missing_optional:
            result.warnings = [f"Optional dependency not available: {dep}" for dep in missing_optional]

        # 检测循环依赖
        cycle_error = self._detect_cycles(plugin_ids)
        if cycle_error:
            result.success = False
            result.errors.append(cycle_error)
            return result

        # 构建依赖图（只包含必需依赖）
        graph = self._build_dependency_graph(plugin_ids)

        # 执行拓扑排序
        try:
            sorted_ids = self._topological_sort(graph, plugin_ids)
            result.load_order = sorted_ids
            result.unload_order = list(reversed(sorted_ids))
        except DependencyError as e:
            result.success = False
            result.errors.append(str(e))

        return result

    def resolve_load_order(self, plugin_ids: List[str]) -> List[str]:
        """
        解析插件加载顺序
        返回: 按加载顺序排列的插件ID列表
        """
        result = self.resolve(plugin_ids)
        if not result.success:
            raise DependencyError("; ".join(result.errors))
        return result.load_order

    def resolve_unload_order(self, plugin_ids: List[str]) -> List[str]:
        """
        解析插件卸载顺序（与加载顺序相反）
        返回: 按卸载顺序排列的插件ID列表
        """
        result = self.resolve(plugin_ids)
        if not result.success:
            raise DependencyError("; ".join(result.errors))
        return result.unload_order

    def get_load_order_with_priority(self, plugin_ids: List[str]) -> List[str]:
        """
        考虑优先级的加载顺序
        优先级高的插件先加载，后卸载
        """
        # 按优先级分组
        by_priority: Dict[PluginPriority, List[str]] = defaultdict(list)
        for pid in plugin_ids:
            if pid in self._plugins:
                priority = self._plugins[pid].priority
                by_priority[priority].append(pid)

        # 先处理关键和高优先级插件
        result = []
        for priority in sorted(by_priority.keys()):
            pids = by_priority[priority]
            # 在同优先级内按依赖排序
            ordered = self.resolve(pids)
            if ordered.success:
                result.extend(ordered.load_order)
            else:
                result.extend(pids)  # 降级处理

        return result

    def _validate_dependencies(self, plugin_ids: Set[str]) -> Tuple[List[str], List[str]]:
        """
        验证依赖是否存在
        返回: (missing_required, missing_optional)
        """
        missing_required = []
        missing_optional = []
        plugin_ids_set = set(plugin_ids)

        for pid in plugin_ids:
            if pid not in self._plugins:
                continue

            info = self._plugins[pid]

            # 检查必需依赖 - 必须全部存在
            for dep_id in info.dependencies:
                if dep_id not in self._plugins:
                    missing_required.append(f"{pid} requires {dep_id}")
                elif dep_id not in plugin_ids_set:
                    missing_required.append(f"{pid} requires {dep_id} (not in target set)")

            # 检查可选依赖 - 仅警告，不阻止
            for dep_id in info.optional_deps:
                if dep_id not in self._plugins:
                    missing_optional.append(f"{pid} optional dependency {dep_id} not available")

        return missing_required, missing_optional

    def _build_dependency_graph(self, plugin_ids: List[str]) -> Dict[str, List[str]]:
        """
        构建依赖图（只包含必需依赖）
        """
        graph = defaultdict(list)
        plugin_ids_set = set(plugin_ids)

        for pid in plugin_ids:
            if pid in self._plugins:
                # 只包含必需依赖，可选依赖不参与排序
                deps = self._plugins[pid].dependencies
                # 只保留在目标集合中的依赖
                graph[pid] = [d for d in deps if d in plugin_ids_set]

        return graph

    def _detect_cycles(self, plugin_ids: List[str]) -> Optional[str]:
        """
        检测循环依赖
        返回: 错误信息或 None
        """
        graph = self._build_dependency_graph(plugin_ids)
        visited = set()
        rec_stack = set()
        cycle_path = []

        def dfs(node: str) -> Optional[List[str]]:
            visited.add(node)
            rec_stack.add(node)
            cycle_path.append(node)

            for neighbor in graph.get(node, []):
                if neighbor not in visited:
                    if dfs(neighbor):
                        return cycle_path[:]
                elif neighbor in rec_stack:
                    # 发现循环
                    start = cycle_path.index(neighbor)
                    cycle = cycle_path[start:] + [neighbor]
                    return cycle

            cycle_path.pop()
            rec_stack.remove(node)
            return None

        for pid in plugin_ids:
            if pid not in visited:
                cycle = dfs(pid)
                if cycle:
                    return f"Circular dependency detected: {' -> '.join(cycle)}"

        return None

    def _topological_sort(
        self, 
        graph: Dict[str, List[str]], 
        plugin_ids: List[str]
    ) -> List[str]:
        """
        拓扑排序（Kahn算法），考虑优先级
        """
        # 计算入度
        in_degree = defaultdict(int)
        for pid in plugin_ids:
            in_degree[pid] = 0

        for pid in plugin_ids:
            for dep in graph.get(pid, []):
                in_degree[dep] += 1

        # 入度为0的节点队列
        queue = [pid for pid in plugin_ids if in_degree[pid] == 0]

        # 按优先级排序初始队列（优先级低的先处理）
        queue.sort(key=lambda p: (
            self._plugins[p].priority.value if p in self._plugins else 999
        ))

        result = []

        while queue:
            # 取出当前优先级最高的节点（数值小的优先）
            current = queue.pop(0)
            result.append(current)

            # 更新依赖当前节点的节点的入度
            for pid in plugin_ids:
                if current in graph.get(pid, []):
                    in_degree[pid] -= 1
                    if in_degree[pid] == 0:
                        # 按优先级插入到队列中正确位置
                        current_priority = (
                            self._plugins[pid].priority.value 
                            if pid in self._plugins else 999
                        )

                        inserted = False
                        for i, qp in enumerate(queue):
                            qp_priority = (
                                self._plugins[qp].priority.value 
                                if qp in self._plugins else 999
                            )
                            if current_priority < qp_priority:
                                queue.insert(i, pid)
                                inserted = True
                                break

                        if not inserted:
                            queue.append(pid)

        if len(result) != len(plugin_ids):
            raise DependencyError("Failed to resolve all dependencies")

        return result

    def check_compatibility(self, plugin_ids: List[str]) -> List[Tuple[str, str]]:
        """
        检查版本兼容性
        返回: [(plugin_id, warning_message), ...]
        """
        warnings = []
        plugin_ids_set = set(plugin_ids)

        for pid in plugin_ids:
            if pid not in self._plugins:
                continue

            info = self._plugins[pid]

            # 检查API版本兼容性
            for dep_id in info.dependencies:
                if dep_id in self._plugins:
                    dep_info = self._plugins[dep_id]
                    dep_api = dep_info.supported_api_versions
                    if not dep_api:
                        warnings.append((
                            pid, 
                            f"{dep_id} has no declared API versions"
                        ))

            # 检查可选依赖是否可用
            for dep_id in info.optional_deps:
                if dep_id not in self._plugins:
                    warnings.append((
                        pid,
                        f"Optional dependency {dep_id} is not available"
                    ))

        return warnings

    def get_dependency_tree(self, plugin_id: str, include_optional: bool = True) -> Dict:
        """
        获取插件的依赖树
        include_optional: 是否包含可选依赖
        """
        if plugin_id not in self._plugins:
            return {}

        def build_tree(pid: str, visited: Set[str], is_optional: bool = False) -> Dict:
            if pid in visited:
                return {"_cycle": True, "_optional": is_optional}

            visited.add(pid)
            info = self._plugins[pid]

            children = {}

            # 处理必需依赖
            for dep_id in info.dependencies:
                if dep_id in self._plugins:
                    children[dep_id] = build_tree(dep_id, visited.copy(), False)

            # 处理可选依赖
            if include_optional:
                for dep_id in info.optional_deps:
                    if dep_id in self._plugins:
                        children[dep_id] = build_tree(dep_id, visited.copy(), True)
                    else:
                        children[dep_id] = {"_available": False, "_optional": True}

            return {
                "name": info.name,
                "version": info.version,
                "priority": info.priority.name,
                "optional": is_optional,
                "children": children
            }

        return build_tree(plugin_id, set())

    def get_reverse_dependencies(self, plugin_id: str) -> List[str]:
        """
        获取依赖指定插件的所有插件列表
        """
        dependents = []

        for pid, info in self._plugins.items():
            if plugin_id in info.dependencies:
                dependents.append(pid)

        return dependents

