// ============ 基础类型定义 ============

type NodeID string

type Command interface{}

type LogEntry struct {
	Index   int
	Term    int
	Command Command
}

// ServerState 节点状态
type ServerState int

const (
	Follower ServerState = iota
	Candidate
	Leader
)

// Config 节点配置
type Config struct {
	NodeID           NodeID
	Cluster          map[NodeID]string
	ElectionTimeout  time.Duration
	HeartbeatTimeout time.Duration
	Storage          Storage
}

// ============ 存储接口 ============

type Storage interface {
	SaveState(state *PersistentState) error
	LoadState() (*PersistentState, error)
	SaveLog(entries []LogEntry) error
	LoadLog() ([]LogEntry, error)
	SaveSnapshot(snapshot []byte, lastIncludedIndex, lastIncludedTerm int) error
	LoadSnapshot() ([]byte, int, int, error)
}

// MemoryStorage 内存存储（用于测试）
type MemoryStorage struct {
	mu       sync.RWMutex
	state    *PersistentState
	log      []LogEntry
	snapshot []byte
	snapIdx  int
	snapTerm int
}

type PersistentState struct {
	CurrentTerm int
	VotedFor    NodeID
}

func NewMemoryStorage() *MemoryStorage {
	return &MemoryStorage{
		state: &PersistentState{CurrentTerm: 0, VotedFor: ""},
		log:   make([]LogEntry, 0),
	}
}

func (s *MemoryStorage) SaveState(state *PersistentState) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.state = state
	return nil
}

