// NewServer 创建 Raft 节点
func NewServer(config Config, applyCh chan ApplyMsg) *Server {
	s := &Server{
		config:        config,
		state:         Follower,
		log:           make([]LogEntry, 0),
		nextIndex:     make(map[NodeID]int),
		matchIndex:    make(map[NodeID]int),
		applyCh:       applyCh,
		notifyCh:      make(map[string]chan interface{}),
	}

	// 加载持久化状态
	if config.Storage != nil {
		state, _ := config.Storage.LoadState()
		if state != nil {
			s.currentTerm = state.CurrentTerm
			s.votedFor = state.VotedFor
		}
		logEntries, _ := config.Storage.LoadLog()
		if len(logEntries) > 0 {
			s.log = logEntries
		}
	}

	// 初始化选举定时器
	s.electionTimer = time.NewTimer(s.randomizedElectionTimeout())

	return s
}

// Start 启动 Raft 节点
func (s *Server) Start() {
	go s.run()
}

// Kill 停止节点
func (s *Server) Kill() {
	s.chanLock.Lock()
	defer s.chanLock.Unlock()
	if ch, ok := s.notifyCh["kill"]; ok {
		close(ch)
	}
}

// ============ 主循环 ============

func (s *Server) run() {
	for {
		s.mu.Lock()
		state := s.state
		s.mu.Unlock()

		switch state {
		case Follower, Candidate:
			s.runBackupLoop()
		case Leader:
			s.runLeaderLoop()
		}
	}
}

func (s *Server) runBackupLoop() {
	s.mu.Lock()
	timeout := s.randomizedElectionTimeout()
	s.mu.Unlock()

	timer := time.NewTimer(timeout)
	killCh := s.getKillChannel()

	select {
	case <-timer.C:
		s.mu.Lock()
		s.startElection()
		s.mu.Unlock()
	case <-killCh:
		return
	}
}

func (s *Server) getKillChannel() <-chan struct{} {
	s.chanLock.RLock()
	defer s.chanLock.RUnlock()
	if ch, ok := s.notifyCh["kill"]; ok {
		return ch
	}
	// 返回一个永不通用的 channel
	return make(chan struct{})
}

func (s *Server) runLeaderLoop() {
	ticker := time.NewTicker(s.config.HeartbeatTimeout)
	defer ticker.Stop()
	killCh := s.getKillChannel()

	for {
		select {
		case <-ticker.C:
			s.mu.Lock()
			s.sendHeartbeats()
			s.mu.Unlock()
		case <-killCh:
			return
		}
	}
}

// ============ Leader 选举 ============

func (s *Server) randomizedElectionTimeout() time.Duration {
	n, _ := rand.Int(rand.Reader, big.NewInt(150))
	return s.config.ElectionTimeout + time.Duration(n.Int64())*time.Millisecond
}

func (s *Server) startElection() {
	s.state = Candidate
	s.currentTerm++
	s.votedFor = s.config.NodeID
	s.persist()

	lastLogIndex, lastLogTerm := s.lastLogInfo()
	args := RequestVoteArgs{
		Term:         s.currentTerm,
		CandidateID:  s.config.NodeID,
		LastLogIndex: lastLogIndex,
		LastLogTerm:  lastLogTerm,
	}

	s.voteCount = 1 // 给自己投票

	clusterSize := len(s.config.Cluster)
	if clusterSize == 1 {
		// 单一节点集群，直接成为 Leader
		s.becomeLeader()
		return
	}

	// 并行发送投票请求
	for nodeID := range s.config.Cluster {
		if nodeID == s.config.NodeID {
			continue
		}
		go s.sendRequestVote(nodeID, args)
	}
}

func (s *Server) sendRequestVote(target NodeID, args RequestVoteArgs) {
	reply := s.rpcClient.SendRequestVote(target, args)

	s.mu.Lock()
	defer s.mu.Unlock()

	// 检查是否已经变成 Leader 或 term 已过期
	if s.state != Candidate {
		return
	}
	if args.Term != s.currentTerm {
		return
	}

	if reply.VoteGranted {
		s.voteCount++
		majority := len(s.config.Cluster)/2 + 1
		if s.voteCount >= majority {
			s.becomeLeader()
		}
	} else if reply.Term > s.currentTerm {
		s.becomeFollower(reply.Term)
	}
}

func (s *Server) becomeLeader() {
	s.state = Leader
	log.Printf("[Node %s] Became LEADER at term %d", s.config.NodeID, s.currentTerm)

	// 初始化 Leader 状态
	lastIndex := s.lastLogIndex()
	for nodeID := range s.config.Cluster {
		s.nextIndex[nodeID] = lastIndex + 1
		s.matchIndex[nodeID] = 0
	}
	// 确保自己的 matchIndex 正确
	s.matchIndex[s.config.NodeID] = lastIndex
}

func (s *Server) becomeFollower(term int) {
	s.state = Follower
	s.currentTerm = term
	s.votedFor = ""
	s.persist()
	log.Printf("[Node %s] Became FOLLOWER at term %d", s.config.NodeID, s.currentTerm)
}

// HandleRequestVote 处理投票请求
func (s *Server) HandleRequestVote(args RequestVoteArgs) RequestVoteReply {
	s.mu.Lock()
	defer s.mu.Unlock()

	reply := RequestVoteReply{Term: s.currentTerm, VoteGranted: false}

	// 如果 term 更小，拒绝投票
	if args.Term < s.currentTerm {
		return reply
	}

	// 如果收到更高 term，转变为 Follower
	if args.Term > s.currentTerm {
		s.becomeFollower(args.Term)
	}

	// 检查是否应该投票
	canVote := s.votedFor == "" || s.votedFor == args.CandidateID
	lastLogIndex, lastLogTerm := s.lastLogInfo()

	// Raft 投票规则：candidate 的日志至少和 receiver 的日志一样新
	logOk := args.LastLogTerm > lastLogTerm ||
		(args.LastLogTerm == lastLogTerm && args.LastLogIndex >= lastLogIndex)

	if canVote && logOk {
		reply.VoteGranted = true
		s.votedFor = args.CandidateID
		s.persist()
		log.Printf("[Node %s] Voted for %s", s.config.NodeID, args.CandidateID)
	}

	return reply
}

