// lastLogInfo 返回最后一个日志条目的索引和 term
func (s *Server) lastLogInfo() (int, int) {
	if len(s.log) == 0 {
		return 0, 0
	}
	lastEntry := s.log[len(s.log)-1]
	return lastEntry.Index, lastEntry.Term
}

// lastLogIndex 返回最后一个日志条目的索引
func (s *Server) lastLogIndex() int {
	if len(s.log) == 0 {
		return 0
	}
	return s.log[len(s.log)-1].Index
}

// raftIndexToSliceIndex 将 Raft 的 1-based 索引转换为 slice 的 0-based 索引
func (s *Server) raftIndexToSliceIndex(raftIndex int) int {
	return raftIndex - 1
}

// StartCommand 提交命令到 Leader
func (s *Server) StartCommand(command Command) (int, int, bool) {
	s.mu.Lock()
	defer s.mu.Unlock()

	if s.state != Leader {
		return 0, 0, false
	}

	newEntry := LogEntry{
		Index:   s.lastLogIndex() + 1,
		Term:    s.currentTerm,
		Command: command,
	}
	s.log = append(s.log, newEntry)
	s.persist()

	log.Printf("[Leader %s] Appended command at index %d, term %d", 
		s.config.NodeID, newEntry.Index, newEntry.Term)
	return newEntry.Index, newEntry.Term, true
}

func (s *Server) sendHeartbeats() {
	for nodeID := range s.config.Cluster {
		if nodeID == s.config.NodeID {
			continue
		}
		go s.replicateToPeer(nodeID)
	}
}

func (s *Server) replicateToPeer(target NodeID) {
	s.mu.Lock()

	// 计算 prevLogIndex 和 prevLogTerm
	prevLogIndex := s.nextIndex[target] - 1
	var prevLogTerm int
	if prevLogIndex > 0 {
		prevLogTerm = s.log[s.raftIndexToSliceIndex(prevLogIndex)].Term
	}

	// 收集需要复制的日志条目
	entries := make([]LogEntry, 0)
	lastIndex := s.lastLogIndex()
	if s.nextIndex[target] <= lastIndex {
		entries = append(entries, s.log[s.raftIndexToSliceIndex(s.nextIndex[target]):]...)
	}

	args := AppendEntriesArgs{
		Term:         s.currentTerm,
		LeaderID:     s.config.NodeID,
		PrevLogIndex: prevLogIndex,
		PrevLogTerm:  prevLogTerm,
		Entries:      entries,
		LeaderCommit: s.commitIndex,
	}
	s.mu.Unlock()

	reply := s.rpcClient.SendAppendEntries(target, args)

	s.mu.Lock()
	defer s.mu.Unlock()

	// 检查是否还是 Leader，term 是否匹配
	if args.Term != s.currentTerm || s.state != Leader {
		return
	}

	if reply.Success {
		// 更新 nextIndex 和 matchIndex
		newNextIndex := args.PrevLogIndex + len(entries) + 1
		s.nextIndex[target] = newNextIndex
		s.matchIndex[target] = newNextIndex - 1

		// 更新 commitIndex
		s.updateCommitIndex()
	} else if reply.Term > s.currentTerm {
		s.becomeFollower(reply.Term)
	} else {
		// 日志不匹配，递减 nextIndex 重试
		s.nextIndex[target]--
	}
}

// HandleAppendEntries 处理日志追加请求
func (s *Server) HandleAppendEntries(args AppendEntriesArgs) AppendEntriesReply {
	s.mu.Lock()
	defer s.mu.Unlock()

	reply := AppendEntriesReply{Term: s.currentTerm, Success: false}

	// 1. Term 检查
	if args.Term < s.currentTerm {
		reply.MatchIndex = s.lastLogIndex()
		return reply
	}
	if args.Term > s.currentTerm {
		s.becomeFollower(args.Term)
	}

	// 2. 重置选举定时器（在新 term 成为 Follower 后）
	// 注意：在真实实现中，这里应该重置外部的选举定时器

	// 3. 检查 prevLogIndex 处的日志是否匹配
	lastIndex := s.lastLogIndex()

	if args.PrevLogIndex == 0 {
		// PrevLogIndex 为 0 表示这是第一条日志之前的空条目，总是匹配的
		// 继续处理
	} else if args.PrevLogIndex > lastIndex {
		// Follower 的日志太短
		reply.Success = false
		reply.MatchIndex = lastIndex
		return reply
	} else {
		// 检查 prevLogIndex 处的 term 是否匹配
		sliceIdx := s.raftIndexToSliceIndex(args.PrevLogIndex)
		if s.log[sliceIdx].Term != args.PrevLogTerm {
			// Term 不匹配，说明从 prevLogIndex 开始的日志都不需要了
			// 删除冲突条目
			s.log = s.log[:sliceIdx]
			s.persist()
			reply.MatchIndex = args.PrevLogIndex - 1
			reply.Success = false
			return reply
		}
	}

	// 4. 处理日志追加（处理冲突并追加新条目）
	if len(args.Entries) > 0 {
		// 从 PrevLogIndex 位置开始处理日志
		// 保留 PrevLogIndex 及其之前的日志，追加新条目
		appendStart := s.raftIndexToSliceIndex(args.PrevLogIndex + 1)

		// 确保 slice 足够长
		if appendStart >= len(s.log) {
			// 直接追加
			s.log = append(s.log, args.Entries...)
		} else {
			// 有冲突覆盖的情况
			// 保留前面的日志
			s.log = append(s.log[:appendStart], args.Entries...)
		}
		s.persist()
	}

	// 5. 更新 commitIndex
	if args.LeaderCommit > s.commitIndex {
		if args.LeaderCommit < s.lastLogIndex() {
			s.commitIndex = args.LeaderCommit
		} else {
			s.commitIndex = s.lastLogIndex()
		}
		s.applyToStateMachine()
	}

	reply.Success = true
	reply.MatchIndex = s.lastLogIndex()
	return reply
}

func (s *Server) updateCommitIndex() {
	// 只有当前 term 的日志才能被提交
	// 从高索引向低索引扫描，找到大多数节点拥有的日志
	for n := s.lastLogIndex(); n > s.commitIndex; n-- {
		// 只有当前 term 的日志可以被提交
		sliceIdx := s.raftIndexToSliceIndex(n)
		if s.log[sliceIdx].Term != s.currentTerm {
			continue
		}

		count := 1 // 自己的日志
		for nodeID := range s.config.Cluster {
			if nodeID == s.config.NodeID {
				continue
			}
			if s.matchIndex[nodeID] >= n {
				count++
			}
		}

		majority := len(s.config.Cluster)/2 + 1
		if count >= majority {
			s.commitIndex = n
			break
		}
	}

	s.applyToStateMachine()
}

func (s *Server) applyToStateMachine() {
	for s.lastApplied < s.commitIndex {
		s.lastApplied++
		sliceIdx := s.raftIndexToSliceIndex(s.lastApplied)
		entry := s.log[sliceIdx]
		s.applyCh <- ApplyMsg{
			CommandValid: true,
			Command:      entry.Command,
			CommandIndex: entry.Index,
			CommandTerm:  entry.Term,
		}
	}
}

