@dataclass
class DIDDocument:
    """DID文档 (W3C DID Core) - 修复版"""

    context: List[str] = field(default_factory=lambda: [
        "https://www.w3.org/ns/did/v1",
        "https://w3id.org/security/v1"
    ])
    id: str = ""
    also_known_as: List[str] = field(default_factory=list)
    controller: List[str] = field(default_factory=list)
    verification_method: List[VerificationMethod] = field(default_factory=list)
    authentication: List[str] = field(default_factory=list)
    assertion_method: List[str] = field(default_factory=list)
    key_agreement: List[str] = field(default_factory=list)
    capability_invocation: List[str] = field(default_factory=list)
    capability_delegation: List[str] = field(default_factory=list)
    service: List[ServiceEndpoint] = field(default_factory=list)
    created: Optional[str] = None
    updated: Optional[str] = None
    version_id: Optional[str] = None

    def to_dict(self) -> Dict:
        """
        修复后的序列化方法 - 正确映射属性名
        """
        result = {
            "@context": self.context
        }

        result["id"] = self.id

        if self.also_known_as:
            result["alsoKnownAs"] = self.also_known_as

        if self.controller:
            result["controller"] = self.controller

        if self.verification_method:
            result["verificationMethod"] = [vm.to_dict() for vm in self.verification_method]

        # 正确的属性映射表
        attr_mapping = {
            "authentication": self.authentication,
            "assertionMethod": self.assertion_method,
            "keyAgreement": self.key_agreement,
            "capabilityInvocation": self.capability_invocation,
            "capabilityDelegation": self.capability_delegation
        }

        for json_key, attr_value in attr_mapping.items():
            if attr_value:
                result[json_key] = attr_value

        if self.service:
            result["service"] = [s.to_dict() for s in self.service]

        if self.created:
            result["created"] = self.created
        if self.updated:
            result["updated"] = self.updated
        if self.version_id:
            result["versionId"] = self.version_id

        return result

    @classmethod
    def from_dict(cls, data: Dict) -> 'DIDDocument':
        """从字典反序列化"""
        vm_list = [VerificationMethod.from_dict(vm) for vm in data.get("verificationMethod", [])]
        service_list = [ServiceEndpoint.from_dict(s) for s in data.get("service", [])]

        return cls(
            context=data.get("@context", []),
            id=data.get("id", ""),
            also_known_as=data.get("alsoKnownAs", []),
            controller=data.get("controller", []),
            verification_method=vm_list,
            authentication=data.get("authentication", []),
            assertion_method=data.get("assertionMethod", []),
            key_agreement=data.get("keyAgreement", []),
            capability_invocation=data.get("capabilityInvocation", []),
            capability_delegation=data.get("capabilityDelegation", []),
            service=service_list,
            created=data.get("created"),
            updated=data.get("updated"),
            version_id=data.get("versionId")
        )

    def to_json(self) -> str:
        """序列化为JSON字符串"""
        return json.dumps(self.to_dict(), indent=2, ensure_ascii=False)

    @classmethod
    def from_json(cls, json_str: str) -> 'DIDDocument':
        """从JSON字符串反序列化"""
        return cls.from_dict(json.loads(json_str))

    def get_verification_method_by_id(self, vm_id: str) -> Optional[VerificationMethod]:
        """根据ID获取验证方法"""
        for vm in self.verification_method:
            if vm.id == vm_id:
                return vm
        return None

    def get_service_by_type(self, service_type: str) -> Optional[ServiceEndpoint]:
        """根据类型获取服务"""
        for service in self.service:
            if service.type == service_type:
                return service
        return None


