class ProofGenerator:
    """证明生成器"""

    @staticmethod
    def create_proof(
        document: Dict,
        private_key_bytes: bytes,
        key_type: KeyType,
        verification_method_id: str,
        proof_purpose: str = "assertionMethod",
        challenge: Optional[str] = None,
        domain: Optional[str] = None
    ) -> Proof:
        """创建密码学证明"""
        now = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())

        # 准备签名数据
        signing_data = ProofGenerator._prepare_signing_data(
            document, proof_purpose, challenge, domain
        )

        # 签名
        signature = CryptoUtils.sign(signing_data, private_key_bytes, key_type)
        proof_value = base64.b64encode(signature).decode('ascii')

        return Proof(
            type="EcdsaSecp256k1Signature2019",
            created=now,
            verification_method=verification_method_id,
            proof_purpose=proof_purpose,
            proof_value=proof_value,
            challenge=challenge,
            domain=domain
        )

    @staticmethod
    def _prepare_signing_data(
        document: Dict,
        proof_purpose: str,
        challenge: Optional[str],
        domain: Optional[str]
    ) -> bytes:
        """准备签名数据"""
        proof_config = {
            "type": "EcdsaSecp256k1Signature2019",
            "verificationMethod": document.get("verificationMethod", 
                document.get("verificationMethod", [{}])[0].get("id", "") if isinstance(document.get("verificationMethod"), list) else ""),
            "proofPurpose": proof_purpose
        }

        if challenge:
            proof_config["challenge"] = challenge
        if domain:
            proof_config["domain"] = domain

        # 规范化并哈希
        proof_bytes = json.dumps(proof_config, separators=(',', ':'), sort_keys=True).encode('utf-8')
        document_bytes = json.dumps(document, separators=(',', ':'), sort_keys=True).encode('utf-8')

        # 合并并哈希
        combined = hashlib.ssha256(proof_bytes + document_bytes)
        return combined.digest()


class ProofVerifier:
    """证明验证器"""

    @staticmethod
    def verify_proof(
        document: Dict,
        proof: Proof,
        public_key_bytes: bytes,
        key_type: KeyType
    ) -> bool:
        """验证证明"""
        # 移除proof后的文档
        doc_without_proof = {k: v for k, v in document.items() if k != "proof"}

        # 重建签名数据
        signing_data = ProofGenerator._prepare_signing_data(
            doc_without_proof, proof.proof_purpose, proof.challenge, proof.domain
        )

        # 解码签名
        if not proof.proof_value:
            return False

        signature = base64.b64decode(proof.proof_value)

        # 验证签名
        return CryptoUtils.verify(signing_data, signature, public_key_bytes, key_type)


