class DIDMethod:
    """DID方法基类"""

    METHOD_NAME: str = ""

    @staticmethod
    def generate_id() -> str:
        """生成唯一的DID标识"""
        random_bytes = secrets.token_bytes(16)
        return CryptoUtils.hash_sha256(random_bytes)[:32]

    @staticmethod
    def create_did(method_name: str, method_specific_id: str) -> str:
        """创建DID"""
        return f"did:{method_name}:{method_specific_id}"

    @classmethod
    def parse_did(cls, did: str) -> Tuple[str, str, str]:
        """解析DID字符串"""
        parts = did.split(":")
        if len(parts) != 3:
            raise ValueError(f"Invalid DID format: {did}")
        return parts[0], parts[1], parts[2]


